namespace sv_9b399787b9a2405e90875293b99cf8c2.Models;

public class WizardData
{
    // Step 1 – Personal Info
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2 – Experience
    public List<JobEntry> JobHistory { get; set; } = new();

    // Step 3 – References
    public List<ReferenceContact> References { get; set; } = new();

    /// <summary>Steps the user has explicitly saved (1-based).</summary>
    public HashSet<int> CompletedSteps { get; set; } = new();
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Duration { get; set; } = "";
}

public class ReferenceContact
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
    public string Relationship { get; set; } = "";
}

using System.Collections.Concurrent;
using sv_9b399787b9a2405e90875293b99cf8c2.Models;

namespace sv_9b399787b9a2405e90875293b99cf8c2.Services;

/// <summary>
/// Singleton store that holds wizard data keyed by ASP.NET Core session ID.
/// Both the static-SSR layout and interactive-server pages resolve the same
/// instance, giving them a shared view of each applicant's progress.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardData> _store = new();

    public WizardData GetOrCreate(string sessionId)
        => _store.GetOrAdd(sessionId, _ => new WizardData());

    public void Remove(string sessionId)
        => _store.TryRemove(sessionId, out _);
}

