arguments.file_text:
@inherits LayoutComponentBase
@inject NavigationManager Nav
@inject sv_9b399787b9a2405e90875293b99cf8c2.Services.WizardStateStore Store

@{
    var steps = new (string Url, string Label)[]
    {
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience",    "Experience"),
        ("/apply/references",    "References"),
        ("/apply/review",        "Review"),
    };

    var currentPath = new Uri(Nav.Uri).AbsolutePath.TrimEnd('/');
    int currentStep = 0;
    for (int i = 0; i < steps.Length; i++)
    {
        if (currentPath.Equals(steps[i].Url, StringComparison.OrdinalIgnoreCase))
        {
            currentStep = i + 1;
            break;
        }
    }

    // Read completed-step data from the store using the session ID.
    var sessionId = HttpContext?.Session?.Id;
    HashSet<int> completed = new();
    if (!string.IsNullOrEmpty(sessionId))
    {
        completed = Store.GetOrCreate(sessionId).CompletedSteps;
    }
}

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            <span class="wizard-step-label me-auto">
                @if (currentStep > 0)
                {
                    <strong>Step @currentStep of @steps.Length</strong>
                }
            </span>
            <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
        </div>

        @if (currentStep > 0)
        {
            <nav class="wizard-progress px-4 py-3" aria-label="Wizard progress">
                <ol class="wizard-steps">
                    @for (int i = 0; i < steps.Length; i++)
                    {
                        var step = steps[i];
                        int stepNum = i + 1;
                        string css = stepNum == currentStep
                            ? "active"
                            : completed.Contains(stepNum) ? "completed" : "";

                        <li class="wizard-step @css">
                            <a href="@step.Url">
                                <span class="step-number">@stepNum</span>
                                <span class="step-label">@step.Label</span>
                            </a>
                        </li>
                    }
                </ol>
            </nav>
        }

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    [CascadingParameter]
    public HttpContext? HttpContext { get; set; }
}

.page {
    position: relative;
    display: flex;
    flex-direction: column;
}

main {
    flex: 1;
}

.sidebar {
    background-image: linear-gradient(180deg, rgb(5, 39, 103) 0%, #3a0647 70%);
}

.top-row {
    background-color: #f7f7f7;
    border-bottom: 1px solid #d6d5d5;
    height: 3.5rem;
    display: flex;
    align-items: center;
}

    .top-row ::deep a, .top-row ::deep .btn-link {
        white-space: nowrap;
        margin-left: 1.5rem;
        text-decoration: none;
    }

    .top-row ::deep a:hover, .top-row ::deep .btn-link:hover {
        text-decoration: underline;
    }

/* ── Wizard progress bar ── */

.wizard-progress {
    background: #f0f0f0;
    border-bottom: 1px solid #d6d5d5;
}

.wizard-steps {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    gap: 0.25rem;
    counter-reset: none;
}

.wizard-step {
    flex: 1;
    text-align: center;
}

    .wizard-step a {
        display: flex;
        align-items: center;
        justify-content: center;
        gap: 0.5rem;
        text-decoration: none;
        color: #888;
        padding: 0.4rem 0.5rem;
        border-radius: 0.375rem;
        transition: background 0.15s;
    }

    .wizard-step a:hover {
        background: #e2e2e2;
    }

    .wizard-step .step-number {
        display: inline-flex;
        align-items: center;
        justify-content: center;
        width: 1.75rem;
        height: 1.75rem;
        border-radius: 50%;
        border: 2px solid #ccc;
        font-weight: 600;
        font-size: 0.85rem;
        flex-shrink: 0;
    }

    .wizard-step.active a {
        color: #0d6efd;
        font-weight: 600;
    }

    .wizard-step.active .step-number {
        border-color: #0d6efd;
        background: #0d6efd;
        color: #fff;
    }

    .wizard-step.completed a {
        color: #198754;
    }

    .wizard-step.completed .step-number {
        border-color: #198754;
        background: #198754;
        color: #fff;
    }

.wizard-step-label {
    font-size: 0.9rem;
    color: #555;
}

@media (max-width: 640.98px) {
    .top-row {
        justify-content: space-between;
    }

    .top-row ::deep a, .top-row ::deep .btn-link {
        margin-left: 0;
    }

    .wizard-step .step-label {
        display: none;
    }
}

@media (min-width: 641px) {
    .page {
        flex-direction: row;
    }

    .sidebar {
        width: 250px;
        height: 100vh;
        position: sticky;
        top: 0;
    }

    .top-row {
        position: sticky;
        top: 0;
        z-index: 1;
    }

    .top-row, article {
        padding-left: 2rem !important;
        padding-right: 1.5rem !important;
    }
}

#blazor-error-ui {
    color-scheme: light only;
    background: lightyellow;
    bottom: 0;
    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
    box-sizing: border-box;
    display: none;
    left: 0;
    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
    position: fixed;
    width: 100%;
    z-index: 1000;
}

    #blazor-error-ui .dismiss {
        cursor: pointer;
        position: absolute;
        right: 0.75rem;
        top: 0.5rem;
    }

