@page "/apply/personal-info"
@rendermode InteractiveServer
@layout WizardLayout

@inject sv_9b399787b9a2405e90875293b99cf8c2.Services.WizardStateStore Store
@inject NavigationManager Nav
@inject PersistentComponentState PersistentState

<PageTitle>Personal Info – Apply</PageTitle>

<h1>Personal Information</h1>

<EditForm Model="this" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3" style="max-width:400px">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="_name" />
    </div>
    <div class="mb-3" style="max-width:400px">
        <label class="form-label">Email Address</label>
        <InputText class="form-control" @bind-Value="_email" />
    </div>

    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    [CascadingParameter] public HttpContext? HttpContext { get; set; }

    private string _sessionId = "";
    private PersistingComponentStateSubscription _sub;

    private string _name = "";
    private string _email = "";

    protected override void OnInitialized()
    {
        _sub = PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("wizardSessionId", _sessionId);
            return Task.CompletedTask;
        });

        if (!PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
            _sessionId = HttpContext?.Session?.Id ?? "";
        else
            _sessionId = restored ?? "";

        if (!string.IsNullOrEmpty(_sessionId))
        {
            var data = Store.GetOrCreate(_sessionId);
            _name = data.Name;
            _email = data.Email;
        }
    }

    private void Next()
    {
        if (string.IsNullOrEmpty(_sessionId)) return;
        var data = Store.GetOrCreate(_sessionId);
        data.Name = _name;
        data.Email = _email;
        data.CompletedSteps.Add(1);
        Nav.NavigateTo("/apply/experience");
    }

    public void Dispose() => _sub.Dispose();
}

