@page "/apply/review"
@rendermode InteractiveServer
@layout WizardLayout

@inject sv_9b399787b9a2405e90875293b99cf8c2.Services.WizardStateStore Store
@inject NavigationManager Nav
@inject PersistentComponentState PersistentState

<PageTitle>Review – Apply</PageTitle>

<h1>Review Your Application</h1>

@if (_data is null)
{
    <p>Loading…</p>
}
else
{
    <section class="mb-4">
        <h4>Personal Information <a href="/apply/personal-info" class="btn btn-sm btn-outline-secondary ms-2">Edit</a></h4>
        <dl class="row" style="max-width:500px">
            <dt class="col-sm-3">Name</dt>
            <dd class="col-sm-9">@_data.Name</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@_data.Email</dd>
        </dl>
    </section>

    <section class="mb-4">
        <h4>Experience <a href="/apply/experience" class="btn btn-sm btn-outline-secondary ms-2">Edit</a></h4>
        @if (_data.JobHistory.Count == 0)
        {
            <p class="text-muted">No jobs added.</p>
        }
        else
        {
            <ul class="list-group" style="max-width:500px">
                @foreach (var job in _data.JobHistory)
                {
                    <li class="list-group-item">
                        <strong>@job.Title</strong> at @job.Company
                        <span class="text-muted">(@job.Duration)</span>
                    </li>
                }
            </ul>
        }
    </section>

    <section class="mb-4">
        <h4>References <a href="/apply/references" class="btn btn-sm btn-outline-secondary ms-2">Edit</a></h4>
        @if (_data.References.Count == 0)
        {
            <p class="text-muted">No references added.</p>
        }
        else
        {
            <ul class="list-group" style="max-width:500px">
                @foreach (var r in _data.References)
                {
                    <li class="list-group-item">
                        @r.Name – @r.Email
                        <span class="text-muted">(@r.Relationship)</span>
                    </li>
                }
            </ul>
        }
    </section>

    <div class="mt-3">
        <a href="/apply/references" class="btn btn-outline-secondary me-2">← Back</a>
        <button class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>

    @if (_submitted)
    {
        <div class="alert alert-success mt-3">Your application has been submitted!</div>
    }
}

@code {
    [CascadingParameter] public HttpContext? HttpContext { get; set; }

    private string _sessionId = "";
    private PersistingComponentStateSubscription _sub;

    private sv_9b399787b9a2405e90875293b99cf8c2.Models.WizardData? _data;
    private bool _submitted;

    protected override void OnInitialized()
    {
        _sub = PersistentState.RegisterOnPersisting(() =>
        {
            PersistentState.PersistAsJson("wizardSessionId", _sessionId);
            return Task.CompletedTask;
        });

        if (!PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
            _sessionId = HttpContext?.Session?.Id ?? "";
        else
            _sessionId = restored ?? "";

        if (!string.IsNullOrEmpty(_sessionId))
            _data = Store.GetOrCreate(_sessionId);
    }

    private void Submit()
    {
        if (_data is null) return;
        _data.CompletedSteps.Add(4);
        _submitted = true;
        // In a real app you'd persist to a database and call Store.Remove(_sessionId).
    }

    public void Dispose() => _sub.Dispose();
}

